import React from 'react'

function ImageSlider(props) {
    return (
        <div>
            {props.images.map((image,index)=>(
                <div key={index}>
                    <img style={{height:'140px',width:'200'}}src={`http://localhost:5000/${image}`} alt="productImage" />
                </div>
            ))}
        </div>
    )
}

export default ImageSlider
